UPDATE tb_auth_grp
SET auth_grp_nm = #{authGrpNm}
   ,auth_grp_expl = #{authGrpExpl}
   ,use_yn = #{useYn}
   ,upt_user_seq = #{uptUserSeq}
   ,upt_date_time = now()
WHERE auth_grp_seq = #{authGrpSeq}

UPDATE tb_auth
SET auth_nm = #{authNm}
   ,auth_expl = #{authExpl}
   ,use_yn = #{useYn}
   ,upt_user_seq = #{uptUserSeq}
   ,upt_date_time = now()
WHERE auth_seq = #{authSeq}

UPDATE tb_auth_user
SET use_yn = #{useYn}
   ,str_dt = #{strDt}
   ,end_dt = #{endDt}
   ,upt_user_seq = #{uptUserSeq}
   ,upt_date_time = now()
WHERE auth_user_seq = #{authUserSeq}
